import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Reference appendix","description":"App URLs, faucet links, Arbiscan, deployed contract addresses, and a glossary for the MuHaven Testing Guide.","frontmatter":{"title":"Reference appendix","description":"App URLs, faucet links, Arbiscan, deployed contract addresses, and a glossary for the MuHaven Testing Guide."},"headers":[],"relativePath":"guide/reference.md","filePath":"guide/reference.md","lastUpdated":1780205082000}'),d={name:"guide/reference.md"};function n(s,t,i,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="reference-appendix" tabindex="-1">Reference appendix <a class="header-anchor" href="#reference-appendix" aria-label="Permalink to &quot;Reference appendix&quot;">​</a></h1><p>Everything you might need to look up while testing.</p><h2 id="app-urls" tabindex="-1">App URLs <a class="header-anchor" href="#app-urls" aria-label="Permalink to &quot;App URLs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What</th><th>URL</th></tr></thead><tbody><tr><td><strong>Dashboard (production)</strong></td><td><a href="https://muhaven.app" target="_blank" rel="noreferrer">muhaven.app</a></td></tr><tr><td>Sign in</td><td><a href="https://muhaven.app/login" target="_blank" rel="noreferrer">muhaven.app/login</a></td></tr><tr><td>HavenBot chat</td><td><a href="https://muhaven.app/agent" target="_blank" rel="noreferrer">muhaven.app/agent</a></td></tr><tr><td><strong>Documentation</strong></td><td><a href="https://docs.muhaven.app" target="_blank" rel="noreferrer">docs.muhaven.app</a></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Always register your passkey on the domain you&#39;ll test on.</p><p>A passkey created on one domain won&#39;t work on another. For the public app, register on <a href="https://muhaven.app" target="_blank" rel="noreferrer">muhaven.app</a>. See <a href="/guide/troubleshooting#passkey-rp-id">Troubleshooting</a>.</p></div><h2 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Chain</strong></td><td>Arbitrum Sepolia (testnet)</td></tr><tr><td><strong>Chain ID</strong></td><td><code>421614</code></td></tr><tr><td><strong>Block explorer</strong></td><td><a href="https://sepolia.arbiscan.io" target="_blank" rel="noreferrer">sepolia.arbiscan.io</a></td></tr><tr><td><strong>Gas</strong></td><td>Sponsored — you never need ETH</td></tr></tbody></table><h2 id="faucets-get-testnet-funds" tabindex="-1">Faucets (get testnet funds) <a class="header-anchor" href="#faucets-get-testnet-funds" aria-label="Permalink to &quot;Faucets (get testnet funds)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Where</th><th>Notes</th></tr></thead><tbody><tr><td><strong>USDC</strong></td><td><a href="https://faucet.circle.com/" target="_blank" rel="noreferrer">faucet.circle.com</a></td><td>Select <strong>Arbitrum Sepolia</strong>. This is the only token you need.</td></tr><tr><td>ETH / gas</td><td><em>Not needed</em></td><td>MuHaven sponsors gas via a paymaster.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Faucet rate limits are the most common stall.</p><p>Circle&#39;s faucet drips a fixed amount per address per time window. If it refuses you, either wait the cooldown or fund a second address. You only need a small amount (e.g. $100 of test USDC) to exercise the whole guide. See <a href="/guide/troubleshooting#faucet-limits">Troubleshooting → Faucet</a>.</p></div><h2 id="is-there-a-pre-funded-demo-account" tabindex="-1">Is there a pre-funded demo account? <a class="header-anchor" href="#is-there-a-pre-funded-demo-account" aria-label="Permalink to &quot;Is there a pre-funded demo account?&quot;">​</a></h2><p><strong>No shared login.</strong> MuHaven authenticates with <strong>passkeys</strong>, which are bound to your physical device and can&#39;t be handed out. Every tester creates their own account in under a minute (<a href="/guide/investor/sign-in">I1</a>) and funds it from the faucet (<a href="/guide/investor/get-funds">I2</a>). This is by design — it&#39;s a live platform with no shared credentials.</p><h2 id="deployed-contracts-arbitrum-sepolia" tabindex="-1">Deployed contracts (Arbitrum Sepolia) <a class="header-anchor" href="#deployed-contracts-arbitrum-sepolia" aria-label="Permalink to &quot;Deployed contracts (Arbitrum Sepolia)&quot;">​</a></h2><p>These are public on-chain addresses — open any of them on <a href="https://sepolia.arbiscan.io" target="_blank" rel="noreferrer">sepolia.arbiscan.io</a>. All MuHaven contracts are upgradeable proxies.</p><h3 id="platform-singletons" tabindex="-1">Platform singletons <a class="header-anchor" href="#platform-singletons" aria-label="Permalink to &quot;Platform singletons&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Contract</th><th>Address</th><th>Role</th></tr></thead><tbody><tr><td><strong>MuHavenStable (mhUSDC)</strong></td><td><code>0xF9bc25b67238C870255c33EC75fA37A09C00edE7</code></td><td>Confidential USDC wrapper; the currency for buys &amp; yield</td></tr><tr><td><strong>MuHavenSubscription</strong></td><td><code>0x39D49B2614d24ba189B613bEAa903d829A73eA9e</code></td><td>Atomic buy / redeem coordinator</td></tr><tr><td><strong>TokenRegistry</strong></td><td><code>0x4915E9Aa034244e299fb1609792D66b9fFAbf885</code></td><td>Per-token configuration registry</td></tr><tr><td><strong>InvestorRegistry</strong></td><td><code>0xE7D4CB42EdB19e268e5e8a10d1A02f321Bfa50D0</code></td><td>Holder enumeration (drives yield)</td></tr><tr><td><strong>YieldSnapshot</strong></td><td><code>0xaC4163f84db2C85333D5aF6f87848d7362A59887</code></td><td>Pull-based yield distribution</td></tr><tr><td><strong>IssuerControlledOracle</strong></td><td><code>0xD30069114dFC83C714B04d6036dEfa64d2E9d583</code></td><td>NAV oracle (issuer-written)</td></tr></tbody></table><h3 id="external-token" tabindex="-1">External token <a class="header-anchor" href="#external-token" aria-label="Permalink to &quot;External token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Address</th></tr></thead><tbody><tr><td><strong>USDC (Circle, Arb Sepolia)</strong></td><td><code>0x75faf114eafb1BDbe2F0316DF893fd58CE46AA4d</code></td></tr></tbody></table><h3 id="example-rwa-token-cetes" tabindex="-1">Example RWA token (CETES) <a class="header-anchor" href="#example-rwa-token-cetes" aria-label="Permalink to &quot;Example RWA token (CETES)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Contract</th><th>Address</th></tr></thead><tbody><tr><td><strong>MuHavenToken (CETES)</strong></td><td><code>0xF3945c52DB79eBc6BFEA1dc460Ead77D70858B43</code></td></tr><tr><td>MuHavenTreasury (CETES)</td><td><code>0xEd596e61A22f3099a21dFD2C07BEEDbcbd3a7c74</code></td></tr><tr><td>RedemptionQueue (CETES)</td><td><code>0x3f8D8350EEE036f6FbEA64B68886cEd11cF28ddC</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">The marketplace lists many more tokens.</p><p>CETES is one example. The live <a href="/guide/investor/marketplace">marketplace</a> carries a rotating set of tokenized treasuries, gold, money-market funds, and tokenized equities. Each token&#39;s detail page links its on-chain address.</p></div><h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>mhUSDC</strong></td><td>MuHaven&#39;s confidential USDC wrapper (contract: <em>MuHavenStable</em>). Encrypted balance; the settlement currency for every flow. Always written <code>mhUSDC</code>.</td></tr><tr><td><strong>fhERC-20</strong></td><td>An encrypted ERC-20: balances are ciphertext (<code>euint128</code>) on-chain. MuHaven&#39;s RWA tokens are fhERC-20.</td></tr><tr><td><strong>FHE / CoFHE</strong></td><td>Fully Homomorphic Encryption. MuHaven uses <strong>Fhenix CoFHE</strong> — a coprocessor on Arbitrum that computes on encrypted values and decrypts asynchronously.</td></tr><tr><td><strong>Passkey</strong></td><td>A device-bound WebAuthn credential (Touch ID, Windows Hello, security key). Your login and your signer — there&#39;s no password or seed phrase.</td></tr><tr><td><strong>Kernel / ZeroDev</strong></td><td>Your smart account (ERC-4337) created by ZeroDev and controlled by your passkey. Enables sponsored gas and scoped session keys.</td></tr><tr><td><strong>Scoped session key</strong></td><td>A short-lived, narrowly-permissioned key you grant the agent so it can execute <em>within your policy</em> without holding your passkey.</td></tr><tr><td><strong>How the agent acts</strong></td><td>Either it proposes and you approve each action with your passkey (a dashboard deep-link), or — with a Scoped session you granted — it executes autonomously within your per-trade cap.</td></tr><tr><td><strong>NAV</strong></td><td>Net Asset Value per share, set by the issuer&#39;s oracle. A buy reverts if the NAV is stale.</td></tr><tr><td><strong>Redemption queue</strong></td><td>When an instant sell exceeds the per-epoch instant cap, the overflow is queued and settles in a later epoch.</td></tr><tr><td><strong>KYC / ERC-3643</strong></td><td>The compliance whitelist. On testnet, a dev-mode bypass lets you transfer freely.</td></tr><tr><td><strong>Epoch</strong></td><td>One yield-distribution round for a token. Investors claim their share from a settled epoch.</td></tr></tbody></table><p>→ Need to fix something? <a href="/guide/troubleshooting"><strong>Troubleshooting &amp; FAQ</strong></a></p>',24)])])}const g=e(d,[["render",n]]);export{u as __pageData,g as default};
